type Items = Array<{
        /**
         *  Значение у item
         */
        value: string | number;
        /**
         * Метка-подпись к item
         */
        label: string;
        /**
        * Сторона открытия вложенного дропдауна относительно текущего элемента;
        */
        placement?: DropdownPlacement;
        /**
         * Список дочерних items.
         */
        items?: Items;
        /**
         * Item не активен
         */
        disabled?: boolean;
        /**
         * Слот для контента слева
         */
        contentLeft?: ReactNode;
        /**
         * Слот для контента справа
         */
        contentRight?: ReactNode;
        /**
        * Отобразить ли разделитель до элемента
        */
        dividerBefore?: boolean;
        /**
        * Отобразить ли разделитель после элемента
        */
        dividerAfter?: boolean;
        /**
         * Выбранный item.
         * @deprecated использовать ContentLeft || ContentRight
         */
        isActive?: boolean;
        /**
         * Кастомный цвет текста
         * @deprecated
         */
        color?: string;
        /**
         * Item не активен
         * @deprecated использовать disabled
         */
        isDisabled?: boolean;
    }>;

import React from 'react';
import { Button, Dropdown } from '@salutejs/plasma-web';
export function App() {
    const items = [
        {
            value: 'north_america',
            label: 'Северная Америка',
        },
        {
            value: 'south_america',
            label: 'Южная Америка',
            items: [
                {
                    value: 'brazil',
                    label: 'Бразилия',
                    items: [
                        {
                            value: 'rio_de_janeiro',
                            label: 'Рио-де-Жанейро',
                        },
                        {
                            value: 'sao_paulo',
                            label: 'Сан-Паулу',
                        },
                    ],
                },
                {
                    value: 'argentina',
                    label: 'Аргентина',
                },
            ],
        },
    ];
    return (
        <div style={{ height:"300px" }}>
            <Dropdown
                items={items}
            >
                <Button text="Список стран" />
            </Dropdown>
        </div>
    );
}

